static int proc_put_long(void __user **buf, size_t *size, unsigned long val,

			  bool neg)

{

	int len;

	char tmp[TMPBUFLEN], *p = tmp;



	sprintf(p, "%s%lu", neg ? "-" : "", val);

	len = strlen(tmp);

	if (len > *size)

		len = *size;

	if (copy_to_user(*buf, tmp, len))

		return -EFAULT;

	*size -= len;

	*buf += len;

	return 0;

