import { expect } from 'chai';

import { deepCopy, deepExtend } from '../src/deepCopy';



describe('deepCopy()', () => {

  it('Scalars', () => {

    expect(deepCopy(true)).to.equal(true);

    expect(deepCopy(123)).to.equal(123);

    expect(deepCopy('abc')).to.equal('abc');

  });



  it('Date', () => {

    const d = new Date();

    expect(deepCopy(d)).to.deep.equal(d);

  });



  it('Object', () => {

    expect(deepCopy({})).to.deep.equal({});

    expect(deepCopy({ a: 123 })).to.deep.equal({ a: 123 });

    expect(deepCopy({ a: { b: 123 } })).to.deep.equal({ a: { b: 123 } });

  });



  it('Array', () => {

    expect(deepCopy([])).to.deep.equal([]);

    expect(deepCopy([123, 456])).to.deep.equal([123, 456]);

    expect(deepCopy([123, [456]])).to.deep.equal([123, [456]]);

  });

});



describe('deepExtend', () => {

  it('Scalars', () => {

    expect(deepExtend(1, true)).to.equal(true);

    expect(deepExtend(undefined, 123)).to.equal(123);

    expect(deepExtend('was', 'abc')).to.equal('abc');

  });



  it('Date', () => {

    const d = new Date();

    expect(deepExtend(new Date(), d)).to.deep.equal(d);

  });



  it('Object', () => {

    expect(deepExtend({ old: 123 }, {})).to.deep.equal({ old: 123 });

    expect(deepExtend({ old: 123 }, { s: 'hello' })).to.deep.equal({

      old: 123,

      s: 'hello'

    });

    expect(

      deepExtend({ old: 123, a: { c: 'in-old' } }, { a: { b: 123 } })

    ).to.deep.equal({ old: 123, a: { b: 123, c: 'in-old' } });

  });



  it('Array', () => {

    expect(deepExtend([1], [])).to.deep.equal([]);

    expect(deepExtend([1], [123, 456])).to.deep.equal([123, 456]);

    expect(deepExtend([1], [123, [456]])).to.deep.equal([123, [456]]);

  });



  it('Array is copied - not referenced', () => {

    const o1 = { a: [1] };

    const o2 = { a: [2] };



    expect(deepExtend(o1, o2)).to.deep.equal({ a: [2] });

    o2.a.push(3);

    expect(o1).to.deep.equal({ a: [2] });

  });



  it('Array with undefined elements', () => {

    const a: any = [];

    a[3] = '3';

    const b = deepExtend(undefined, a);

    expect(b).to.deep.equal([, , , '3']);

  });



  it('Function', () => {

    const source: any = (): void => {

      /*_*/

    };

    const target: any = deepExtend(

      {

        a: () => {

          /*_*/

        }

      },

      { a: source }

    );

    expect({ a: source }).to.deep.equal(target);

    expect(source).to.equal(target.a);

  });



  it('does not extend property __proto__', () => {

    const src = JSON.parse('{ "__proto__": { "polluted": "polluted" } }');

    const a: Record<string, unknown> = {};

    deepExtend(a, src);



    expect(a.__proto__).to.equal(Object.prototype);

    expect(a.polluted).to.be.undefined;

  });

});,None,Non-Vulnerable,None,False

#

# multibytecodec_support.py

#   Common Unittest Routines for CJK codecs

#



import codecs

import os

import re

import sys

import unittest

from http.client import HTTPException

from test import support

from io import BytesIO



class TestBase:

    encoding        = ''   # codec name

    codec           = None # codec tuple (with 4 elements)

    tstring         = None # must set. 2 strings to test StreamReader



    codectests      = None # must set. codec test tuple

    roundtriptest   = 1    # set if roundtrip is possible with unicode

    has_iso10646    = 0    # set if this encoding contains whole iso10646 map

    xmlcharnametest = None # string to test xmlcharrefreplace

    unmappedunicode = '\udeee' # a unicode code point that is not mapped.



    def setUp(self):

        if self.codec is None:

            self.codec = codecs.lookup(self.encoding)

        self.encode = self.codec.encode

        self.decode = self.codec.decode

        self.reader = self.codec.streamreader

        self.writer = self.codec.streamwriter

        self.incrementalencoder = self.codec.incrementalencoder

        self.incrementaldecoder = self.codec.incrementaldecoder



    def test_chunkcoding(self):

        tstring_lines = []

        for b in self.tstring:

            lines = b.split(b"\n")

            last = lines.pop()

            assert last == b""

            lines = [line + b"\n" for line in lines]

            tstring_lines.append(lines)

        for native, utf8 in zip(*tstring_lines):

            u = self.decode(native)[0]

            self.assertEqual(u, utf8.decode('utf-8'))

            if self.roundtriptest:

                self.assertEqual(native, self.encode(u)[0])



    def test_errorhandle(self):

        for source, scheme, expected in self.codectests:

            if isinstance(source, bytes):

                func = self.decode

            else:

                func = self.encode

            if expected:

                result = func(source, scheme)[0]

                if func is self.decode:

                    self.assertTrue(type(result) is str, type(result))

                    self.assertEqual(result, expected,

                                     '%a.decode(%r, %r)=%a != %a'

                                     % (source, self.encoding, scheme, result,

                                        expected))

                else:

                    self.assertTrue(type(result) is bytes, type(result))

                    self.assertEqual(result, expected,

                                     '%a.encode(%r, %r)=%a != %a'

                                     % (source, self.encoding, scheme, result,

                                        expected))

            else:

                self.assertRaises(UnicodeError, func, source, scheme)



    def test_xmlcharrefreplace(self):

        if self.has_iso10646:

            self.skipTest('encoding contains full ISO 10646 map')



        s = "\u0b13\u0b23\u0b60 nd eggs"

        self.assertEqual(

            self.encode(s, "xmlcharrefreplace")[0],

            b"&#2835;&#2851;&#2912; nd eggs"

        )



    def test_customreplace_encode(self):

        if self.has_iso10646:

            self.skipTest('encoding contains full ISO 10646 map')



        from html.entities import codepoint2name



        def xmlcharnamereplace(exc):

            if not isinstance(exc, UnicodeEncodeError):

                raise TypeError("don't know how to handle %r" % exc)

            l = []

            for c in exc.object[exc.start:exc.end]:

                if ord(c) in codepoint2name:

                    l.append("&%s;" % codepoint2name[ord(c)])

                else:

                    l.append("&#%d;" % ord(c))

            return ("".join(l), exc.end)



        codecs.register_error("test.xmlcharnamereplace", xmlcharnamereplace)



        if self.xmlcharnametest:

            sin, sout = self.xmlcharnametest

        else:

            sin = "\xab\u211c\xbb = \u2329\u1234\u232a"

            sout = b"&laquo;&real;&raquo; = &lang;&#4660;&rang;"

        self.assertEqual(self.encode(sin,

                                    "test.xmlcharnamereplace")[0], sout)



    def test_callback_returns_bytes(self):

        def myreplace(exc):

            return (b"1234", exc.end)

        codecs.register_error("test.cjktest", myreplace)

        enc = self.encode("abc" + self.unmappedunicode + "def", "test.cjktest")[0]

        self.assertEqual(enc, b"abc1234def")



    def test_callback_wrong_objects(self):

        def myreplace(exc):

            return (ret, exc.end)

        codecs.register_error("test.cjktest", myreplace)



        for ret in ([1, 2, 3], [], None, object()):

            self.assertRaises(TypeError, self.encode, self.unmappedunicode,

                              'test.cjktest')



    def test_callback_long_index(self):

        def myreplace(exc):

            return ('x', int(exc.end))

        codecs.register_error("test.cjktest", myreplace)

        self.assertEqual(self.encode('abcd' + self.unmappedunicode + 'efgh',

                                     'test.cjktest'), (b'abcdxefgh', 9))



        def myreplace(exc):

            return ('x', sys.maxsize + 1)

