  ASSERT(!deferred_end_stream_headers_);

  if (!pending_responses_.empty()) {

    Buffer::OwnedImpl buffer;

    buffer.add(data, length);

    pending_responses_.front().decoder_->decodeData(buffer, false);

  }

}



