	archive_string_copy(&(dest->aes_mbs), &(src->aes_mbs));

	archive_string_copy(&(dest->aes_utf8), &(src->aes_utf8));

	archive_wstring_copy(&(dest->aes_wcs), &(src->aes_wcs));

