int fuse_open_common(struct inode *inode, struct file *file, bool isdir)

{

	struct fuse_conn *fc = get_fuse_conn(inode);

	int err;

	bool lock_inode = (file->f_flags & O_TRUNC) &&

			  fc->atomic_o_trunc &&

			  fc->writeback_cache;



	err = generic_file_open(inode, file);

	if (err)

