	return iw_malloc_ex(ctx,IW_MALLOCFLAG_ZEROMEM,n);

},None,Non-Vulnerable,None,False

IW_IMPL(void*) iw_realloc(struct iw_context *ctx, void *oldmem,

	size_t oldmem_size, size_t newmem_size)

