    TcpSession *ssn = (TcpSession *)p->flow->protoctx;

    if (ssn == NULL)

        SCReturn;



    StreamTcpReturnStreamSegments(&ssn->client);

    StreamTcpReturnStreamSegments(&ssn->server);



    SCReturn;

